=<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <style>
    body { font-family: 'Segoe UI', Arial, sans-serif; background: #f4f0eb; margin: 0; padding: 0; }
    .wrapper { max-width: 600px; margin: 30px auto; background: #ffffff; border-radius: 16px; overflow: hidden; box-shadow: 0 4px 20px rgba(0,0,0,0.1); }
    .header { background: #1A3C34; padding: 32px 40px; text-align: center; }
    .header h1 { color: #C9A96E; font-family: Georgia, serif; font-size: 28px; margin: 0; letter-spacing: 3px; }
    .header p { color: rgba(255,255,255,0.7); font-size: 13px; margin: 6px 0 0; letter-spacing: 2px; }
    .badge { display: inline-block; background: #C9A96E; color: #1A3C34; font-weight: 700; font-size: 11px; letter-spacing: 1px; padding: 4px 14px; border-radius: 20px; margin-top: 16px; }
    .body { padding: 36px 40px; }
    .section-title { font-size: 11px; font-weight: 700; letter-spacing: 2px; color: #C9A96E; text-transform: uppercase; margin-bottom: 12px; }
    .info-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 16px; margin-bottom: 28px; }
    .info-block { background: #f9f6f2; border-radius: 10px; padding: 14px 18px; }
    .info-block .label { font-size: 10px; color: #999; font-weight: 600; letter-spacing: 1px; text-transform: uppercase; margin-bottom: 4px; }
    .info-block .value { font-size: 15px; color: #1A3C34; font-weight: 600; }
    .divider { border: none; border-top: 1px solid #f0ebe3; margin: 24px 0; }
    .dates-row { display: flex; gap: 16px; margin-bottom: 28px; }
    .date-card { flex: 1; background: #1A3C34; border-radius: 10px; padding: 16px 20px; color: white; text-align: center; }
    .date-card .d-label { font-size: 10px; letter-spacing: 1px; opacity: 0.7; text-transform: uppercase; margin-bottom: 6px; }
    .date-card .d-value { font-size: 16px; font-weight: 700; }
    .source-badge { display: inline-block; padding: 4px 12px; border-radius: 20px; font-size: 11px; font-weight: 700; }
    .source-web { background: #e8f4fd; color: #2980b9; }
    .source-presencial { background: #eafaf1; color: #27ae60; }
    .footer { background: #f9f6f2; padding: 24px 40px; text-align: center; }
    .footer p { color: #999; font-size: 12px; margin: 0; }
  </style>
</head>
<body>
  <div class="wrapper">
    <div class="header">
      <h1>HOTEL MERECURE</h1>
      <p>CRAVO NORTE · ARAUCA</p>
      <div class="badge">⭐ NUEVA RESERVA</div>
    </div>
    <div class="body">
      <p class="section-title">Información del huésped</p>
      <div class="info-grid">
        <div class="info-block"><div class="label">Nombre</div><div class="value">{{ $('Obtener Huésped').item.json[0].first_name }} {{ $('Obtener Huésped').item.json[0].last_name }}</div></div>
        <div class="info-block"><div class="label">Documento</div><div class="value">{{ $('Obtener Huésped').item.json[0].document_number }}</div></div>
        <div class="info-block"><div class="label">Teléfono</div><div class="value">{{ $('Obtener Huésped').item.json[0].phone || 'No registrado' }}</div></div>
        <div class="info-block"><div class="label">Correo</div><div class="value">{{ $('Obtener Huésped').item.json[0].email || 'No registrado' }}</div></div>
      </div>
      <hr class="divider">
      <p class="section-title">Detalle de la reserva</p>
      <div class="info-grid">
        <div class="info-block"><div class="label">Habitación</div><div class="value">#{{ $('Obtener Habitación').item.json[0].room_number }} · Piso {{ $('Obtener Habitación').item.json[0].floor }}</div></div>
        <div class="info-block"><div class="label">Tipo</div><div class="value">{{ $('Obtener Habitación').item.json[0].room_type }}</div></div>
        <div class="info-block"><div class="label">Personas</div><div class="value">{{ $('Webhook Supabase').item.json.body.record.num_guests }} persona(s)</div></div>
        <div class="info-block"><div class="label">Canal</div><div class="value"><span class="source-badge source-{{ $('Webhook Supabase').item.json.body.record.source }}">{{ $('Webhook Supabase').item.json.body.record.source === 'web' ? '🌐 Web' : '🏨 Presencial' }}</span></div></div>
      </div>
      <div class="dates-row">
        <div class="date-card"><div class="d-label">Check-in</div><div class="d-value">{{ $('Webhook Supabase').item.json.body.record.check_in }}</div></div>
        <div class="date-card"><div class="d-label">Check-out</div><div class="d-value">{{ $('Webhook Supabase').item.json.body.record.check_out }}</div></div>
      </div>
      {{ $('Webhook Supabase').item.json.body.record.notes ? '<div class="info-block"><div class="label">Notas</div><div class="value">' + $('Webhook Supabase').item.json.body.record.notes + '</div></div>' : '' }}
    </div>
    <div class="footer">
      <p>Hotel Merecure · Calle 2 #2-32, Cravo Norte, Arauca</p>
      <p style="margin-top:6px">Este correo fue generado automáticamente</p>
    </div>
  </div>
</body>
</html>
